1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const FIRST_INSURANCE_RATE = 0.1;
29	const CURSE_RATE = 0.5;
30	const PROCESSING_FEE = 5;
31	
32	const COMPONENT_PREMIUM = 25;
33	const BLOCK_SIZE = 3;
34	const BLOCK_PREMIUM = 60;
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const componentBasePremium = (count: number): number =>
38	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
39	
40	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
41	
42	const countByType = (items: Item[]): Map<string, number> =>
43	  items.reduce(
44	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
45	    new Map<string, number>(),
46	  );
47	
48	const componentTotal = (items: Item[]): number =>
49	  [...countByType(items.filter(isComponent)).values()].reduce(
50	    (sum, count) => sum + componentBasePremium(count),
51	    0,
52	  );
53	
54	const basePremium = (items: Item[]): number => {
55	  const mainTotal = items
56	    .filter((item) => !isComponent(item))
57	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
58	  return mainTotal + componentTotal(items);
59	};
60	
61	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
62	
63	const curseSurcharge = (items: Item[]): number =>
64	  items
65	    .filter((item) => !isComponent(item) && item.cursed)
66	    .reduce((sum, item) => sum + mainItemBase(item) * CURSE_RATE, 0);
67	
68	const quotePremium = (items: Item[]): number => {
69	  const policyBase = basePremium(items);
70	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
71	  const itemSurcharges = curseSurcharge(items);
72	  return Math.ceil(policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE);
73	};
74	
75	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
76	  const results = scenario.steps.map((step) => ({
77	    premium: quotePremium(step.items),
78	  }));
79	  return { results };
80	};
